// Input: payload Ecowitt GW3000. Due formati possibili:
//  (a) stringa form-urlencoded (default firmware GW3000A_V1.2.0)
//      es: "PASSKEY=...&soilmoisture1=33&soilbatt1=1.7&..."
//  (b) oggetto JSON (inject di test o firmware che pubblica JSON)
// Campi per canale N (1..4):
//   soilmoisture{N}  -> umidita' %  (field value, float)
//   soilbatt{N}      -> tensione V  (field battery_voltage, float)
//   battery_ok       -> derivato da battery_voltage >= 1.1 (bool)
// Nota: 'rssi' non viene scritto (field type conflict con schema legacy).
// Tag: sensor_id=WH51_0N, aiuola=test, position=test.

let raw = msg.payload;

if (typeof raw === 'string') {
    const parsed = {};
    for (const pair of raw.split('&')) {
        if (!pair) continue;
        const eq = pair.indexOf('=');
        if (eq < 0) continue;
        const k = decodeURIComponent(pair.slice(0, eq));
        const v = decodeURIComponent(pair.slice(eq + 1).replace(/\+/g, ' '));
        parsed[k] = v;
    }
    raw = parsed;
}

if (!raw || typeof raw !== 'object') {
    node.warn('Payload non riconosciuto, scarto');
    return null;
}

const CHANNELS = [1, 2, 3, 4];
const BATTERY_OK_THRESHOLD = 1.1;
const out = [];

for (const ch of CHANNELS) {
    const mRaw = raw['soilmoisture' + ch];
    if (mRaw === undefined || mRaw === null || mRaw === '') continue;
    const value = Number(mRaw);
    if (!Number.isFinite(value)) continue;

    const battRaw = raw['soilbatt' + ch];
    const battery_voltage = Number(battRaw);
    const battery_ok = Number.isFinite(battery_voltage) && battery_voltage >= BATTERY_OK_THRESHOLD;

    out.push([
        {
            value: value,
            battery_voltage: Number.isFinite(battery_voltage) ? battery_voltage : 0,
            battery_ok: battery_ok
        },
        {
            sensor_id: 'WH51_0' + ch,
            aiuola: 'test',
            position: 'test'
        }
    ]);
}

if (out.length === 0) {
    node.warn('Nessun canale soilmoisture1..4 valido nel payload');
    return null;
}

return { payload: out, measurement: 'soil_moisture' };

msg.statusCode = 204;
msg.headers = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type',
    'Access-Control-Max-Age': '600'
};
msg.payload = '';
return msg;

// Valida :action e costruisce il payload MQTT per zigbee2mqtt/SWV_valvola/set.
// Output 1: messaggio MQTT (topic + payload JSON)
// Output 2: messaggio HTTP response (CORS + JSON body)

const raw = ((msg.req && msg.req.params && msg.req.params.action) || '').toLowerCase();
const MAP = { on: 'ON', off: 'OFF', toggle: 'TOGGLE' };
const mqttState = MAP[raw];

msg.headers = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type'
};

if (!mqttState) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: `invalid action '${raw}', use on/off/toggle` };
    node.status({ fill: 'red', shape: 'ring', text: `400 '${raw}'` });
    return [null, msg];
}

const mqttMsg = {
    topic: 'zigbee2mqtt/SWV_valvola/set',
    payload: { state: mqttState }
};

msg.statusCode = 200;
msg.payload = { ok: true, action: raw, sent: mqttState };
node.status({ fill: 'blue', shape: 'dot', text: `${raw} @ ${new Date().toISOString().substr(11, 8)}` });

return [mqttMsg, msg];

// Dal payload Z2M estrae i campi di interesse e crea un point InfluxDB
// con tag valve_id=SWV_01 nel measurement 'valve_state'.
const p = msg.payload;
if (!p || typeof p !== 'object') return null;

const fields = { reachable: true };
if (p.state === 'ON' || p.state === 'OFF') fields.state = p.state;
if (Number.isFinite(p.battery)) fields.battery = Number(p.battery);
if (Number.isFinite(p.linkquality)) fields.linkquality = Number(p.linkquality);
if (p.current_device_status) fields.current_device_status = String(p.current_device_status);

// Se abbiamo solo 'reachable' e nient'altro, non scriviamo (evita noise).
if (Object.keys(fields).length <= 1) return null;

return {
    payload: [fields, { valve_id: 'SWV_01' }],
    measurement: 'valve_state'
};

// Safety: se state=ON arma setTimeout che forza OFF dopo SAFETY_MIN minuti.
// Ogni nuovo ON resetta il timer. Ogni OFF (manuale o del safety) lo disarma.
// flow.set('safety_min_override', 0.5) per test veloci (30 sec).

const SAFETY_MIN = Number(flow.get('safety_min_override')) || 15;
const state = msg.payload && msg.payload.state;

let h = context.get('timer');
if (h) { clearTimeout(h); context.set('timer', null); }

if (state === 'ON') {
    const ms = SAFETY_MIN * 60 * 1000;
    const fires_at = new Date(Date.now() + ms);
    const handle = setTimeout(() => {
        node.warn(`SAFETY TIMEOUT ${SAFETY_MIN}min: forcing OFF`);
        node.send({
            topic: 'zigbee2mqtt/SWV_valvola/set',
            payload: { state: 'OFF' },
            _safety: true
        });
        context.set('timer', null);
        node.status({ fill: 'red', shape: 'dot', text: `TIMEOUT fired @ ${new Date().toISOString().substr(11, 8)}` });
    }, ms);
    context.set('timer', handle);
    node.status({ fill: 'yellow', shape: 'dot', text: `armed ${SAFETY_MIN}m (OFF @ ${fires_at.toISOString().substr(11, 5)})` });
} else if (state === 'OFF') {
    node.status({ fill: 'green', shape: 'dot', text: 'disarmed (OFF)' });
}

return null;
